<?php
namespace Tests\Feature\Accounting;
use App\Domain\Accounting\Actions\PostJournal;use App\Domain\Accounting\Actions\ProvisionAccounting;use App\Domain\Accounting\Actions\ReconcileBankStatement;use App\Enums\ReconciliationStatus;use App\Models\BankReconciliation;use App\Models\Cooperative;use App\Models\CooperativeBankAccount;use App\Models\LedgerAccount;use App\Support\Security\ProtectedIdentifier;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class BankReconciliationTest extends TestCase{use RefreshDatabase;public function test_statement_line_can_be_matched_and_reconciliation_completed():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);app(ProvisionAccounting::class)->execute();$cash=LedgerAccount::query()->where('code','1000')->firstOrFail();$liability=LedgerAccount::query()->where('code','2100')->firstOrFail();$protected=app(ProtectedIdentifier::class)->protect('0123456789');$bank=CooperativeBankAccount::query()->create(['ledger_account_id'=>$cash->id,'name'=>'Operating','bank_code'=>'001','bank_name'=>'Test Bank','account_number_encrypted'=>$protected['encrypted'],'account_number_hash'=>$protected['hash'],'account_number_last_four'=>$protected['last_four'],'is_active'=>true]);$entry=app(PostJournal::class)->execute(['reference'=>'BANK-001','entry_date'=>today()->toDateString(),'description'=>'Deposit','lines'=>[['ledger_account_id'=>$cash->id,'debit_minor'=>10000,'credit_minor'=>0],['ledger_account_id'=>$liability->id,'debit_minor'=>0,'credit_minor'=>10000]]]);$reconciliation=BankReconciliation::query()->create(['cooperative_bank_account_id'=>$bank->id,'statement_start_date'=>today(),'statement_end_date'=>today(),'opening_balance_minor'=>0,'closing_balance_minor'=>10000,'status'=>'draft']);$statement=$reconciliation->statementLines()->create(['transaction_date'=>today(),'reference'=>'BANK-001','description'=>'Deposit','amount_minor'=>10000]);$action=app(ReconcileBankStatement::class);$action->match($statement,$entry->lines->first(),10000);$completed=$action->complete($reconciliation);$this->assertSame(ReconciliationStatus::Completed,$completed->status);}}
